INSERT INTO public.qualities (id, name, description, icon_svg) VALUES 
  ('55555555-5555-5555-5555-500000000001', 'Scalability First',       'Architecting systems designed to handle growth and high availability from day zero — proven in production mobility and streaming platforms.', '<svg></svg>'),
  ('55555555-5555-5555-5555-500000000002', 'UX & Design Driven',      'Bridging the gap between engineering and aesthetics. Every interface I build is designed in Figma first, then engineered with precision.', '<svg></svg>'),
  ('55555555-5555-5555-5555-500000000003', 'Full SDLC Ownership',     'From whiteboard to production. I take full technical ownership across conception, architecture, development, testing, and deployment.', '<svg></svg>'),
  ('55555555-5555-5555-5555-500000000004', 'Clean Code Advocate',     'Applying SOLID principles, Clean Architecture, and Domain-Driven Design patterns to every codebase I touch — making it maintainable and testable.', '<svg></svg>')
