('10101010-1010-1010-1010-100000000005', 'DF Center Online Exam System', 'df-center-online-exam', 'web', 'DF Center', '{"url": "/thumb_dfcenter.jpg"}', '{"url": "/thumb_dfcenter.jpg"}', 'Online exam system platform for educational institutions.', '{"raw": "", "text": "A robust online exam system designed to facilitate secure and scalable testing for educational institutions."}', 'https://site.df-center.com/', 'Secure and Scalable Online Exams'),
