('10101010-1010-1010-1010-100000000007', 'Kandengue Atrevido', 'kandengue-atrevido', 'mobile', 'Kandengue Atrevido', '{"url": "/thumb_kandengue.jpg"}', '{"url": "/thumb_kandengue.jpg"}', 'On-demand urban mobility platform connecting drivers and passengers.', '{"raw": "", "text": "A comprehensive urban mobility app offering real-time ride-hailing services with seamless user experience."}', 'https://www.kandengueatrevido.ao/', 'Real-time Urban Mobility'),
('10101010-1010-1010-1010-100000000008', 'Portal dos Intérpretes', 'portal-dos-interpretes', 'web', 'Portal dos Intérpretes', '{"url": "/thumb_portaldosinterpretes.jpg"}', '{"url": "/thumb_portaldosinterpretes.jpg"}', 'Platform for professional interpreters and translation services.', '{"raw": "", "text": "A dedicated portal connecting interpreters with clients, facilitating translation and interpretation services."}', 'https://portaldosinterpretes.com/', 'Interpreter Service Platform'),
('10101010-1010-1010-1010-100000000009', 'Tchossy', 'tchossy', 'web', 'Tchossy', '{"url": "/thumb_tchossy.jpg"}', '{"url": "/thumb_tchossy.jpg"}', 'Institutional website and client management system.', '{"raw": "", "text": "A modern institutional website combined with a client management system for efficient business operations."}', 'https://tchossy.com/', 'Institutional & Client Management'),
('10101010-1010-1010-1010-100000000010', 'Soers Corporation', 'soers-corporation', 'web', 'Soers Corporation', '{"url": "/thumb_soerscorporation.jpg"}', '{"url": "/thumb_soerscorporation.jpg"}', 'Corporate website for Soers Corporation.', '{"raw": "", "text": "A professional corporate website designed to enhance the online presence of Soers Corporation."}', 'https://soerscorporation.ao/', 'Corporate Web Presence') ON CONFLICT DO NOTHING;
INSERT INTO public.project_sections (id, project_id, type, title, subtitle, description, images, items, created_at, updated_at) VALUES
('dde94930-984f-488a-a7b0-4f3dfaca6535', '10101010-1010-1010-1010-100000000005', 'TEXT', 'Vision', 'Project Overview:', '{"raw": "", "text": "A content management system helps you create, manage, and publish content on the web. It also keeps content organized and accessible so it can be used and reused effectively. There are various types of content management systems available - from cloud-based to headless - to meet all audience needs."}', '[]', '[]', '2026-04-05T17:08:39.915137', '2026-04-05T17:08:39.915161'),
('e6bf2fdb-14d0-45a4-9334-10ccd2ff502e', '10101010-1010-1010-1010-100000000005', 'FEATURES', 'Features', 'of this project:', '{"raw": "", "text": "A content management system (CMS) is an application used to manage content, allowing multiple contributors to create, edit, and publish. Content in a CMS is typically stored in a database and displayed in a presentation layer based on a set of templates like a website."}', '[]', '["Content creation and editing", "Workflows, reporting, and content organization", "User and role-based administration and security", "Multilingual content features", "Flexibility, scalability, performance, and analytics"]', '2026-04-05T17:08:39.915189', '2026-04-05T17:08:39.915198'),
('9b69b7b0-bf22-435d-a519-05f8a22d05bf', '10101010-1010-1010-1010-100000000005', 'CHALLENGES', 'Challenges faced', 'in this project:', '{"raw": "", "text": "A content management system (CMS) is an application used to manage content, allowing multiple contributors to create, edit, and publish."}', '[]', '["Content creation and editing", "Workflows, reporting, and content organization", "User and role-based administration and security", "Multilingual content features", "Flexibility, scalability, performance, and analytics"]', '2026-04-05T17:08:39.915218', '2026-04-05T17:08:39.915224'),
('c57b95d0-6171-4ae2-9c78-4bbe995d0c76', '10101010-1010-1010-1010-100000000005', 'SOLUTIONS', 'Solutions to the', 'problems:', '{"raw": "", "text": "A content management system (CMS) is an application used to manage content, allowing multiple contributors to create, edit, and publish."}', '[]', '["Content creation and editing", "Workflows, reporting, and content organization", "User and role-based administration and security", "Multilingual content features", "Flexibility, scalability, performance, and analytics"]', '2026-04-05T17:08:39.915356', '2026-04-05T17:08:39.915362'),
('0bce5eeb-740e-4712-bea5-1b8ecc37de35', '10101010-1010-1010-1010-100000000005', 'FEEDBACK', 'Project Feedback', 'on the project:', '{"raw": "", "text": "Having a content management system for your site allows you to have control over your content. It means having the ability to update, change, or delete any image, text, video, or audio. It allows you to keep your site organized, up-to-date, and looking good."}', '[]', '[]', '2026-04-05T17:08:39.915376', '2026-04-05T17:08:39.915383'),
